// Map Breakcold status name → Setclone outcome value. Returns null when no
// match — the IF node downstream will skip the API call.
const body = $input.first().json.body || $input.first().json;
const statusName = (body.status?.name || body.status_name || body.new_status || '').trim();
const leadId = body.lead_id || body.lead?.id;
const messageId = body.message_id || null;        // optional, only when n8n knows which message triggered
const dealValue = body.deal_value ?? null;        // optional numeric
const note = body.note || null;
const configRow = $('Config map (Breakcold status → outcome)').first().json;

const MAPPING = {
  rdv_triggered: configRow.status_to_outcome_rdv_triggered,
  rdv_signed: configRow.status_to_outcome_rdv_signed,
  rdv_no_show: configRow.status_to_outcome_rdv_no_show,
  rdv_lost: configRow.status_to_outcome_rdv_lost,
};

let outcome = null;
for (const [outcomeKey, breakcoldStatusName] of Object.entries(MAPPING)) {
  if (breakcoldStatusName && breakcoldStatusName.toLowerCase() === statusName.toLowerCase()) {
    outcome = outcomeKey;
    break;
  }
}

return [{ json: { lead_id: leadId, outcome, status_name: statusName, message_id: messageId, deal_value: dealValue, note } }];
